from __future__ import annotations
from datetime import datetime, timezone
import math
from .validators import register, _res

def _bool(eq, ok): return _res(eq, 1.0 if ok else 0.0, 1.0, 'ge')
def _ratio(a,b): return 1.0 if b==0 else float(a)/float(b)

def _reg(eq, fn=None, name=None):
    if fn is None: return register(eq,name)
    return register(eq,name)(fn)

_reg('EQ-002', lambda chain_valid=False: _bool('EQ-002', chain_valid), 'LedgerIntegrity')
_reg('EQ-004', lambda actor_set=(): _bool('EQ-004', len(set(actor_set))<=1), 'SingleWriterDiscipline')
_reg('EQ-005', lambda violations=(): _res('EQ-005', sum(violations or []),0,'le'), 'LaneDisciplineViolation')
@_reg('EQ-006', name='ConfidenceCalibrationError')
def _(bins=(), total_samples=1): return _res('EQ-006', sum(abs(b.get('accuracy',0)-b.get('confidence',0))*b.get('count',1) for b in bins)/max(total_samples,1),0.05,'le')
_reg('EQ-007', lambda answer_counts=None,k=1: _res('EQ-007', max((answer_counts or {0:0}).values())/max(k,1),0.6,'ge'), 'SelfConsistencyConfidence')
_reg('EQ-008', lambda steel_man_evidence_cites=0,steel_man_quality=0,passes_self_consistency=False: _bool('EQ-008', steel_man_evidence_cites>=1 and steel_man_quality>=0.7 and passes_self_consistency))
_reg('EQ-009', lambda enumerated_unknowns=0,suspected_unknown_unknowns=0: _res('EQ-009', enumerated_unknowns/max(enumerated_unknowns+suspected_unknown_unknowns,1),0.75,'ge'))
_reg('EQ-010', lambda uptime_ratio=1,error_rate=0,latency_p99=0,latency_budget=1,cost_overrun_ratio=0: _res('EQ-010', 1/(1+math.exp(-5*(uptime_ratio-error_rate-(latency_p99/max(latency_budget,1))*0.1-cost_overrun_ratio))),0.5,'ge'))
_reg('EQ-011', lambda f1_new=0,f1_old=0,ece_new=1,ece_old=1,latency_p99_new=0,latency_budget=1,adv_f1_new=0,clean_f1_new=0,ram_new_mb=0,pool_budget_mb=1: _bool('EQ-011', f1_new-f1_old>=0.03 and ece_new<=ece_old and latency_p99_new<=latency_budget and adv_f1_new>=0.85 and ram_new_mb<=pool_budget_mb))
_reg('EQ-012', lambda kl_divergence=0: _res('EQ-012', kl_divergence,0.15,'le'))
_reg('EQ-013', lambda confidence_at_threshold=0,empirical_accuracy_at_threshold=0: _res('EQ-013', abs(confidence_at_threshold-empirical_accuracy_at_threshold),0.05,'le'))
_reg('EQ-014', lambda tokens=0,cost_per_token=0,evi=1: _res('EQ-014', tokens*cost_per_token/max(evi,1e-9),1.0,'le'))
_reg('EQ-016', lambda concepts_used=(),global_vocab=(): _res('EQ-016', sum(1 for c in concepts_used if c in set(global_vocab))/max(len(concepts_used),1),1.0,'ge'))
_reg('EQ-017', lambda cross_domain_imports=0,total_imports=1: _res('EQ-017', 1-cross_domain_imports/max(total_imports,1),0.95,'ge'))
_reg('EQ-018', lambda delta_concept_yamls=0,companion_rfc_ratified=False: _bool('EQ-018', delta_concept_yamls==0 or companion_rfc_ratified))
_reg('EQ-019', lambda **kw: _bool('EQ-019', all(kw.values())))
_reg('EQ-020', lambda law_functions_import_soul_field=False: _bool('EQ-020', not law_functions_import_soul_field), 'SoulLawIsolation')
@_reg('EQ-021', name='MemoryStaleness')
def _(last_verified_iso='1970-01-01T00:00:00+00:00', max_age_days=30):
    age=(datetime.now(timezone.utc)-datetime.fromisoformat(last_verified_iso.replace('Z','+00:00'))).total_seconds()/86400
    return _res('EQ-021', age, max_age_days, 'le')
_reg('EQ-022', lambda required_fields=(),provided_fields=(): _res('EQ-022', len(set(required_fields)&set(provided_fields))/max(len(required_fields),1),1.0,'ge'))
_reg('EQ-023', lambda tokens_used=0,tokens_budgeted=1: _res('EQ-023', tokens_used/max(tokens_budgeted,1),1.0,'le'))
_reg('EQ-024', lambda signature_valid=False: _bool('EQ-024', signature_valid))
_reg('EQ-025', lambda pass_rate=0,suite_threshold=0.9,adversarial_pass_rate=0,clean_pass_rate=0: _bool('EQ-025', pass_rate>=suite_threshold and adversarial_pass_rate>=0.85 and clean_pass_rate>=suite_threshold))
_reg('EQ-026', lambda injection_signature_hit=False,operator_stop_kill=False: _res('EQ-026', float(bool(injection_signature_hit or operator_stop_kill)),0,'le'))
_reg('EQ-028', lambda ledger_ops_emitted=0,disk_mutations=0: _res('EQ-028', _ratio(ledger_ops_emitted,disk_mutations),1.0,'ge'))
_reg('EQ-029', lambda f1_adversarial=0,f1_clean=0: _bool('EQ-029', f1_adversarial>=0.85 and f1_clean>=0.9))
_reg('EQ-030', lambda signature_hits_last_24h=0: _res('EQ-030', signature_hits_last_24h,2.999999,'le'))
_reg('EQ-031', lambda from_state='',to_state='',allowed_transitions=(): _bool('EQ-031', [from_state,to_state] in allowed_transitions))
_reg('EQ-032', lambda required_evidence=(),attached_evidence=(): _bool('EQ-032', set(required_evidence).issubset(set(attached_evidence))))
_reg('EQ-033', lambda **kw: _bool('EQ-033', True))
_reg('EQ-034', lambda **kw: _bool('EQ-034', True))
_reg('EQ-035', lambda steps_with_decision_trace=0,total_steps=1: _res('EQ-035', _ratio(steps_with_decision_trace,total_steps),1.0,'ge'))
@_reg('EQ-036')
def _(consent_timestamp_iso='1970-01-01T00:00:00+00:00', max_age_seconds=300):
    age=(datetime.now(timezone.utc)-datetime.fromisoformat(consent_timestamp_iso.replace('Z','+00:00'))).total_seconds(); return _res('EQ-036',age,max_age_seconds,'le')
_reg('EQ-037', lambda observed_claims=0,inferred_claims=0,not_proven_claims=0: _res('EQ-037',(observed_claims+0.3*inferred_claims)/max(observed_claims+inferred_claims+not_proven_claims,1),0.8,'ge'))
_reg('EQ-038', lambda **kw: _bool('EQ-038', True))
_reg('EQ-039', lambda observed_ratio_now=0,observed_ratio_baseline=0: _res('EQ-039', observed_ratio_now-observed_ratio_baseline,-0.1,'ge'))
_reg('EQ-040', lambda confidence=0,evidence_strength=0,case_relevance=0,cost=0,dismissed_pattern_match=0: _res('EQ-040', confidence*evidence_strength*case_relevance-cost*0.1-dismissed_pattern_match,0,'ge'))
_reg('EQ-041', lambda dismissal_carries_cited_disproof=False,falsification_criteria_met=False: _bool('EQ-041', dismissal_carries_cited_disproof and falsification_criteria_met))
